def _parse_dt_any(s: str) -> datetime | None:
    if not s:
        return None
    s = str(s).strip()
    if not s:
        return None
    if s.endswith("Z"):
        s = s[:-1]
    try:
        return datetime.fromisoformat(s)
    except Exception:
        pass
    try:
        if len(s) == 10 and s[4] == "-" and s[7] == "-":
            return datetime.fromisoformat(s + "T00:00:00")
    except Exception:
        pass
    return None


def _log_sync_cache_write_profile(logger: Any, elapsed_ms: int) -> None:
    if int(elapsed_ms or 0) < 250:
        return
    logger.info("[SYNC-DEBUG] local cache write took %dms", int(elapsed_ms or 0))
    try:
        from app.core.db import get_last_db_write_profile

        profile = get_last_db_write_profile("save_sync_cache_delta")
        if profile:
            logger.info("[SYNC-DEBUG] local cache write profile=%s", profile)
    except Exception:
        logger.debug("[SYNC-DEBUG] local cache write profile unavailable", exc_info=True)


def _should_defer_ultra_reconnects(trigger_source: str) -> bool:
    normalized = str(trigger_source or "").strip().upper()
    return normalized in {"CHANGE_DETECTOR", "FAST_PATCH_BUNDLE", "SYNC_NOW_API"}


def check_zkemkeeper_registration() -> Dict[str, Any]:
    """
    Returns a diagnostic dict about ZKEMKeeper COM registration.
    Works without pywin32 by reading registry; optionally tries COM activation if
    pywin32 or comtypes exists.
    """
    result: Dict[str, Any] = {
        "ok": False,
        "windows": (os.name == "nt"),
        "pythonBits": (64 if (8 * (8 if hasattr(__import__("struct"), "calcsize") else 8)) else None),
        "progId": "zkemkeeper.CZKEM",
        "clsid": None,
        "inprocServer32": None,
        "inprocExists": None,
        "registryFound": False,
        "comCreateOk": None,
        "error": None,
        "notes": [],
    }

    if os.name != "nt":
        result["error"] = "Not Windows (COM registration applies on Windows only)."
        return result

    try:
        import struct
        result["pythonBits"] = struct.calcsize("P") * 8
    except Exception:
        result["pythonBits"] = None

    try:
        import winreg

        def _reg_get(path: str, value_name: str | None, wow: int | None) -> str | None:
            # wow: None = default, 32 = WOW6432Node view, 64 = 64-bit view
            access = winreg.KEY_READ
            if wow == 32:
                access |= getattr(winreg, "KEY_WOW64_32KEY", 0)
            elif wow == 64:
                access |= getattr(winreg, "KEY_WOW64_64KEY", 0)

            try:
                with winreg.OpenKey(winreg.HKEY_CLASSES_ROOT, path, 0, access) as k:
                    name = value_name if value_name is not None else ""
                    v, _t = winreg.QueryValueEx(k, name)
                    return str(v) if v is not None else None
            except FileNotFoundError:
                return None
            except OSError:
                return None

        # Try both registry views because many ZKTeco components are 32-bit COM
        views = [None, 32, 64]
        progid_paths = [
            r"zkemkeeper.CZKEM\CLSID",
            r"zkemkeeper.CZKEM.1\CLSID",
        ]

        clsid = None
        clsid_view = None
        for wow in views:
            for p in progid_paths:
                v = _reg_get(p, None, wow)
                if v and v.strip().startswith("{") and v.strip().endswith("}"):
                    clsid = v.strip()
                    clsid_view = wow
                    break
            if clsid:
                break

        if not clsid:
            result["error"] = "ProgID not found in registry (zkemkeeper.CZKEM)."
            return result

        result["registryFound"] = True
        result["clsid"] = clsid
        result["notes"].append(f"ProgID->CLSID found (view={clsid_view}).")

        inproc = None
        inproc_view = None
        for wow in views:
            v = _reg_get(rf"CLSID\{clsid}\InprocServer32", None, wow)
            if v and v.strip():
                inproc = v.strip()
                inproc_view = wow
                break

        result["inprocServer32"] = inproc
        if inproc:
            result["notes"].append(f"InprocServer32 found (view={inproc_view}).")
            try:
                result["inprocExists"] = Path(inproc).exists()
            except Exception:
                result["inprocExists"] = None
        else:
            result["notes"].append("InprocServer32 not found for CLSID (COM may be broken).")

        # Optional COM activation test (works with pywin32 or comtypes)
        try:
            from app.core.zkemkeeper_scanner import (
                create_zkemkeeper_com_object,
                initialize_com_apartment,
            )

            com_cleanup = None
            try:
                com_cleanup = initialize_com_apartment()
                obj, backend = create_zkemkeeper_com_object()
                # If Dispatch succeeded, registration is usable from this Python bitness
                _ = obj is not None
                result["comCreateOk"] = True
                result["ok"] = True
                result["notes"].append(f"COM activation succeeded via {backend}.")
            except Exception as e:
                result["comCreateOk"] = False
                result["error"] = f"COM activation failed: {e}"
            finally:
                if com_cleanup is not None:
                    try:
                        com_cleanup()
                    except Exception:
                        pass
        except Exception:
            result["notes"].append("pywin32/comtypes not installed; skipped COM activation test.")
            # If registry is OK, we still consider it "registered" (but not proven callable)
            result["ok"] = bool(result["registryFound"])

        return result

    except Exception as e:
        result["error"] = f"Registry check failed: {e}"
        return result


def _encoding_to_backend(enc: str) -> str:
    e = (enc or "").strip().lower()
    return "HEX" if e == "hex" else "BASE64"


