        try:
            add_windows_dll_search_paths()
        except Exception:
            pass

        ensure_dirs()
        init_db()

        # Cleanup stale IN_PROGRESS sync runs from the previous session
        # (e.g. the app was killed or crashed mid-sync).
        try:
            from app.core.db import cleanup_stale_in_progress_sync_runs
            _stale = cleanup_stale_in_progress_sync_runs()
            if _stale > 0:
                import logging as _logging
                _logging.getLogger(__name__).info(
                    "[SyncHistory] Cleaned %d stale IN_PROGRESS sync run(s) from previous session", _stale
                )
        except Exception:
            pass

        self.log_queue: "queue.Queue[str]" = queue.Queue()
        self.cfg = load_access_app_config()

        # Resolve SDK DLLs
        try:
            self.cfg.plcomm_dll_path = self._resolve_sdk_dll(self.cfg.plcomm_dll_path)
            self.cfg.zkfp_dll_path = self._resolve_sdk_dll(self.cfg.zkfp_dll_path)
        except Exception as e:
            print(f"SDK resource error: {e}\nPlatform: {platform_summary()}")
            raise

        # Enforce 32-bit requirement
        try:
            require_32bit_python_for_32bit_dll(self.cfg.plcomm_dll_path)
        except Exception as e:
            print(f"Architecture error: {e}\nPlatform: {platform_summary()}")
            raise

        self.logger = setup_logging(self.cfg.log_level, ui_queue=self.log_queue)
        # --- Log upload queue (marker-file based, daemon thread) ---
        try:
            from app.core.log_uploader import LogUploadQueue
            from app.core.logger import HalfDaySizeRotatingFileHandler
            # load_auth_token already imported from access.store at top of file

            self._log_upload_queue = LogUploadQueue(
                log_dir=LOG_DIR,
                get_token=load_auth_token,
                get_upload_url=lambda: (self.cfg.log_presign_url or "").strip(),
            )
            # Wire the callback into the rotating file handler
            for _h in self.logger.handlers:
                if isinstance(_h, HalfDaySizeRotatingFileHandler):
                    _h.on_log_rotated = self._log_upload_queue.register_pending
                    break
            self._log_upload_queue.scan_orphans()
            self._log_upload_queue.start()
            self.logger.info("Log upload queue started (presign_url=%s)", bool(self.cfg.log_presign_url))
        except Exception as _lue:
            # Never crash startup due to upload system
            self.logger.warning("Log upload queue failed to start: %s", _lue)
        self.logger.info("App started.")
        self.logger.info(f"Platform: {platform_summary()}")
        self.logger.info("Data root is managed by app.core.utils (ProgramData/LocalAppData).")
        try:
            config_status = get_access_config_status()
            self.logger.info(
                "Access config: %s (legacyExists=%s migratedAt=%s)",
                config_status.get("liveConfigPath"),
                config_status.get("legacyConfigExists"),
                config_status.get("migratedFromLegacyAt"),
            )
        except Exception:
            self.logger.exception("Failed to read Access config status")
        try:
            storage_status = get_access_storage_status()
            self.logger.info(
                "Access live DB: %s (migration=%s)",
                storage_status.get("liveDbPath"),
                storage_status.get("migrationState"),
            )
        except Exception:
            self.logger.exception("Failed to read Access storage status")
        self.logger.info(f"PullSDK DLL: {self.cfg.plcomm_dll_path}")
        self.logger.info(f"ZKFP DLL  : {self.cfg.zkfp_dll_path}")
