    # ======================= Headless event loop =======================
    def after(self, delay_ms: int, callback) -> int:
        """Schedule callback after delay_ms milliseconds. Returns an ID."""
        with self._sched_lock:
            self._sched_id_counter += 1
            sid = self._sched_id_counter
            target = time.monotonic() + delay_ms / 1000.0
            self._scheduled.append((target, sid, callback))
        return sid

    def after_cancel(self, sid: int) -> None:
        """Cancel a scheduled callback by ID."""
        with self._sched_lock:
            self._scheduled = [(t, i, c) for t, i, c in self._scheduled if i != sid]

    def mainloop(self) -> None:
        """Run the headless event loop. Blocks until quit_app() is called."""
        try:
            while not self._stop_event.is_set():
                now = time.monotonic()
                to_run = []
                with self._sched_lock:
                    remaining = []
                    for t, sid, cb in self._scheduled:
                        if t <= now:
                            to_run.append(cb)
                        else:
                            remaining.append((t, sid, cb))
                    self._scheduled = remaining

                for cb in to_run:
                    try:
                        cb()
                    except KeyboardInterrupt:
                        raise
                    except Exception:
                        if hasattr(self, "logger"):
                            self.logger.exception("Scheduled callback error")

            self._stop_event.wait(timeout=0.05)
        except KeyboardInterrupt:
            if hasattr(self, "logger"):
                self.logger.info("KeyboardInterrupt received, shutting down.")
            self.quit_app()

    def destroy(self) -> None:
        self._stop_event.set()
        if self._change_detector is not None:
            try:
                self._change_detector.stop()
            except Exception:
                pass
        try:
            self._device_sync_engine.stop_workers()
        except Exception:
            pass
        # Shutdown ULTRA engine (with lock to prevent race with sync_tick)
        try:
            with self._ultra_lock:
                if self._ultra_engine and self._ultra_engine.running:
                    self._ultra_engine.stop()
                if self._ultra_history_consumer:
                    self._ultra_history_consumer.stop()
                    self._ultra_history_consumer = None
        except Exception:
            pass

    def quit(self) -> None:
        self._stop_event.set()

    # ======================= Update Manager =======================
    def _ensure_update_manager_started(self, *, check_now: bool) -> None:
        try:
            auth = load_auth_token()
            tok = getattr(auth, "token", None) if auth else None
            tok = str(tok or "").strip()
            if tok:
                self._update_manager.start(token=tok, check_now=check_now)
            else:
                self._update_manager.stop()
        except Exception:
            pass

    def on_update_status_changed(self, st: UpdateStatus) -> None:
        self._update_status = st

    def on_update_ready(self, st: UpdateStatus) -> None:
        try:
            rid = str((st.latest_release or {}).get("releaseId") or "")
            self.logger.info(f"[Access Update] Update ready: releaseId={rid}")
        except Exception:
            pass

    def on_update_error(self, msg: str) -> None:
        try:
            self.logger.warning("[Access Update] %s", msg)
        except Exception:
            pass

    # ======================= SDK DLL resolution =======================
    def _resolve_sdk_dll(self, configured_path: str) -> str:
        s = (configured_path or "").strip()
        if not s:
            raise FileNotFoundError("Empty DLL path in config")
        try:
            return str(resolve_resource_path(s, must_exist=True))
        except Exception:
            pass
        name = Path(s).name
        try:
            return str(resolve_resource_path(name, must_exist=True))
        except Exception as e:
            raise FileNotFoundError(f"Could not resolve DLL '{s}'. Tried by name '{name}' as well. ({e})")

    # ======================= Per-device mode helpers =======================
    def get_access_mode_summary(self) -> Dict[str, int]:
        try:
            from app.core.db import load_sync_device_mode_summary, peek_sync_cache, summarize_access_mode_counts

            cached = peek_sync_cache()
            if cached is not None:
                return summarize_access_mode_counts(getattr(cached, "devices", []) or [])
            return load_sync_device_mode_summary()
        except Exception:
            cache = load_sync_cache()
            devices = getattr(cache, "devices", []) if cache else []
        try:
            from app.core.db import summarize_access_mode_counts

            return summarize_access_mode_counts(devices)
        except Exception:
            dev = ag = ultra = unk = 0
            for d in devices or []:
                if not isinstance(d, dict):
                    continue
                raw = d.get("accessDataMode") or d.get("access_data_mode") or ""
                m = str(raw).strip().upper()
                if m == "DEVICE":
                    dev += 1
                elif m == "AGENT":
                    ag += 1
                elif m == "ULTRA":
                    ultra += 1
                else:
                    unk += 1
            return {"DEVICE": dev, "AGENT": ag, "ULTRA": ultra, "UNKNOWN": unk}

    def _apply_member_shadow_sync(
        self,
        *,
        data: Dict[str, Any],
        refresh: Dict[str, Any],
        delta_changed_ids: set[int] | None,
    ) -> set[int] | None:
        if not refresh.get("members"):
            return delta_changed_ids

        _incoming_users = data.get("users") or []
        _valid_ids_raw = data.get("validMemberIds")
        try:
            from app.core.db import (
                apply_member_shadow_delta,
                diff_member_shadow,
                delete_member_shadow,
                upsert_member_shadow,
            )

            _valid_ids = (
                [int(x) for x in _valid_ids_raw if x is not None]
                if _valid_ids_raw is not None else None
            )

            if data.get("membersDeltaMode"):
                _shadow_deleted = apply_member_shadow_delta(
                    users=_incoming_users,
                    valid_member_ids=_valid_ids,
                )
                deleted_ids = {
                    int(member_id)
                    for member_id in (_shadow_deleted or [])
                    if member_id is not None
                }
                if deleted_ids:
                    merged_ids = set(delta_changed_ids or set())
                    merged_ids.update(deleted_ids)
                    delta_changed_ids = merged_ids
                self.logger.info(
                    "[ShadowDiff] delta fast-path: changed=%d deleted=%d",
                    len(_incoming_users), len(_shadow_deleted),
                )
                return delta_changed_ids

            _diff = diff_member_shadow(
                incoming_users=_incoming_users,
                valid_member_ids=_valid_ids,
            )
            _shadow_changed = set(_diff["new"] + _diff["modified"])
            _shadow_deleted = _diff["deleted"]
            self.logger.info(
                "[ShadowDiff] new=%d modified=%d deleted=%d",
                len(_diff["new"]), len(_diff["modified"]), len(_shadow_deleted),
            )
            if _incoming_users:
                if _shadow_changed:
                    delta_changed_ids = _shadow_changed
                    self.logger.info(
                        "[ShadowDiff] narrowed changed_ids to %d/%d via shadow diff",
                        len(_shadow_changed), len(_incoming_users),
                    )
                elif not _shadow_deleted:
                    delta_changed_ids = set()
                    self.logger.info(
                        "[ShadowDiff] no member changes detected, "
                        "setting changed_ids=empty to skip pin push"
                    )
            upsert_member_shadow(users=_incoming_users)
            if _shadow_deleted:
                delete_member_shadow(active_membership_ids=_shadow_deleted)
            return delta_changed_ids
        except Exception as _shadow_exc:
            self.logger.warning(
                "[ShadowDiff] Error: %s — proceeding with full sync", _shadow_exc
            )
            return delta_changed_ids

    def _request_running_ultra_sync(
        self,
        *,
        refresh: Dict[str, Any],
        changed_ids: set[int] | None,
        device_ids: set[int] | None = None,
        reason: str,
    ) -> bool:
        if not (refresh.get("members") or refresh.get("devices")):
            return False

        normalized_reason = str(reason or "manual").strip().lower() or "manual"
        requested_changed_ids = None
        if refresh.get("devices"):
            requested_changed_ids = None
        elif changed_ids is not None:
            requested_changed_ids = {
                int(member_id)
                for member_id in changed_ids
                if member_id is not None
            }
            if not requested_changed_ids:
                self.logger.info(
                    "[ULTRA] immediate sync skipped: reason=%s changed_ids=0",
                    normalized_reason,
                )
                return False
        requested_device_ids = None
        if device_ids is not None:
            requested_device_ids = {
                int(device_id)
                for device_id in device_ids
                if device_id is not None
            }

        with self._ultra_lock:
            if not self._ultra_engine.running:
                return False
            started = bool(
                self._ultra_engine.request_sync_now(
                    changed_ids=requested_changed_ids,
                    device_ids=requested_device_ids,
                    reason=normalized_reason,
                )
            )

        if started:
            self.logger.info(
                "[ULTRA] immediate sync requested: reason=%s changed_ids=%s device_ids=%s",
                normalized_reason,
                "all" if requested_changed_ids is None else len(requested_changed_ids),
                "all" if requested_device_ids is None else len(requested_device_ids),
            )
        return started

    def _defer_ultra_reconnects(self, *, trigger_source: str, duration_sec: float = 20.0) -> int:
        if not _should_defer_ultra_reconnects(trigger_source):
            return 0
        try:
            with self._ultra_lock:
                ultra_eng = getattr(self, "_ultra_engine", None)
                if not ultra_eng or not getattr(ultra_eng, "running", False):
                    return 0
                deferred = int(
                    ultra_eng.defer_reconnects(
                        duration_sec=float(duration_sec or 0.0),
                        reason=str(trigger_source or "").strip().lower() or "sync",
                    )
                    or 0
                )
            if deferred > 0:
                self.logger.info(
                    "[ULTRA] deferred reconnect attempts during sync: workers=%d trigger_source=%s duration_sec=%.1f",
                    deferred,
                    str(trigger_source or ""),
                    float(duration_sec or 0.0),
                )
            return deferred
        except Exception as exc:
            self.logger.debug("[ULTRA] failed to defer reconnect attempts: %s", exc, exc_info=True)
            return 0

    # ======================= Log polling =======================
    def _poll_logs(self):
        try:
            while True:
                msg = self.log_queue.get_nowait()
                try:
                    # Parse level from log message format: "2026-... | LEVEL | msg"
                    timestamp = None
                    level = "INFO"
                    line = msg
                    if " | " in msg:
                        parts = msg.split(" | ", 2)
                        if len(parts) >= 3:
                            timestamp = parts[0].strip()
                            level = parts[1].strip()
                            line = parts[2]
                        elif len(parts) >= 2:
                            level = parts[1].strip()
                            line = parts[2] if len(parts) > 2 else parts[1]
                    self.page_logs.append_log(level, line, timestamp=timestamp)
                except Exception:
                    self.page_logs.append_log("INFO", str(msg))
        except Exception:
            pass
        self.after(200, self._poll_logs)

    def _build_startup_command(self) -> str | None:
        try:
            if getattr(sys, "frozen", False):
                return f'"{Path(sys.executable)}" {WINDOWS_STARTUP_ARG}'
            return None
        except Exception:
            return None

    def _sync_startup_registration(self) -> None:
        if os.name != "nt":
            return
        try:
            import winreg  # type: ignore
        except Exception:
            return

        enabled = bool(getattr(self.cfg, "start_on_system_startup", False))
        command = self._build_startup_command()
        run_key_path = r"Software\Microsoft\Windows\CurrentVersion\Run"
        value_name = "MonClubAccess"

        try:
            with winreg.OpenKey(winreg.HKEY_CURRENT_USER, run_key_path, 0, winreg.KEY_SET_VALUE) as key:
                if enabled and command:
                    winreg.SetValueEx(key, value_name, 0, winreg.REG_SZ, command)
                    self.logger.info("Access startup registration enabled.")
                else:
                    try:
                        winreg.DeleteValue(key, value_name)
                        self.logger.info("Access startup registration removed.")
                    except FileNotFoundError:
                        pass
                    if enabled and not command:
                        self.logger.info(
                            "Access startup registration skipped because the app is not running from a packaged executable."
                        )
        except Exception:
            self.logger.exception("Failed to synchronize Access startup registration")

    # ======================= Tauri UI =======================
    def _launch_tauri_ui(self):
        _host, port, _enabled = self._effective_local_api_bind()
        # B-001: Pass local API token to Tauri via env var
        import os
        os.environ["MONCLUB_LOCAL_API_TOKEN"] = self._local_api_token
        self._tauri_process = launch_tauri_ui(
            role="access",
            api_port=port,
            logger=self.logger,
            existing_process=self._tauri_process,
            start_hidden=self._started_from_windows_startup,
        )

    def _kill_tauri_ui(self):
        kill_tauri_ui(self._tauri_process, role="access", logger=self.logger)
        self._tauri_process = None

    def quit_app(self):
        # H-003: All stop calls have bounded timeouts to prevent hanging on exit.
        try:
            self._kill_tauri_ui()
        except Exception:
            pass
        try:
            self.stop_realtime_agent()
        except Exception:
            pass
        try:
            self.stop_local_api_server()
        except Exception:
            pass
        try:
            self._update_manager.stop()
        except Exception:
            pass
        try:
            self.destroy()
        except Exception:
            pass
        # Force-exit after 15s if anything is still stuck
        def _force_exit():
            import time, os
            time.sleep(15)
            self.logger.error("Shutdown timed out after 15s — forcing exit")
            os._exit(1)
        _t = threading.Thread(target=_force_exit, daemon=True)
        _t.start()

    def persist_config(self):
        save_access_app_config(self.cfg)
        # Windows-registry write is expensive and AV-scanned. Skip it unless
        # the startup flag actually changed since last sync — most config
        # saves (overlay anchor, sound, tray settings, …) don't touch it.
        try:
            current_startup = bool(getattr(self.cfg, "start_on_system_startup", False))
        except Exception:
            current_startup = False
        last_startup = getattr(self, "_last_synced_startup_flag", None)
        if last_startup != current_startup:
            self._sync_startup_registration()
            self._last_synced_startup_flag = current_startup
        self.logger.info("Access config saved to access/config.json.")

    def publish_feedback_event(self, event_type: str, payload: Dict[str, Any]) -> Dict[str, Any]:
        with self._feedback_events_cond:
            self._feedback_event_seq += 1
            event = {
                "seq": self._feedback_event_seq,
                "type": str(event_type or "").strip(),
                "at": time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime()),
                **dict(payload or {}),
            }
            self._feedback_events.append(event)
            if len(self._feedback_events) > 200:
                self._feedback_events = self._feedback_events[-200:]
            self._feedback_events_cond.notify_all()
            return dict(event)

    def get_feedback_events_since(self, seq: int, *, limit: int = 20) -> List[Dict[str, Any]]:
        with self._feedback_events_cond:
            threshold = int(seq or 0)
            capped_limit = max(1, min(int(limit or 20), 100))
            items = [dict(event) for event in self._feedback_events if int(event.get("seq") or 0) > threshold]
            return items[:capped_limit]

    def _maybe_emit_sync_success_feedback(
        self,
        *,
        sync_run_id: int | None,
        final_status: str,
        trigger_context: SyncTriggerContext,
    ) -> None:
        if sync_run_id is None:
            return
        if str(final_status or "").strip().upper() != "SUCCESS":
            return
        self.publish_feedback_event(
            "sync_completed_success",
            {
                "syncRunId": int(sync_run_id),
                "runType": str(getattr(trigger_context, "run_type", "") or "").strip().upper(),
                "triggerSource": str(getattr(trigger_context, "trigger_source", "") or "").strip().upper(),
            },
        )

