    # ======================= Local API server =======================
    def _effective_local_api_bind(self) -> Tuple[str, int, bool]:
        access_cfg = load_access_config(self.cfg)
        port_cfg = int(access_cfg.local_api_port or 8788)
        enabled_cfg = bool(access_cfg.local_api_enabled)

        gs: Dict[str, Any] = {}
        try:
            gs = get_backend_global_settings() or {}
        except Exception:
            gs = {}

        enabled_backend = bool(gs.get("access_server_enabled", True))
        port_backend = int(gs.get("access_server_port") or 0)

        # B-002: Force loopback-only binding. Ignore backend host overrides.
        # The local API must never bind to 0.0.0.0 or any non-loopback address.
        host = "127.0.0.1"
        port = port_backend if port_backend > 0 else port_cfg
        enabled = bool(enabled_cfg and enabled_backend)

        return host, port, enabled

    def start_local_api_server(self):
        host, port, enabled = self._effective_local_api_bind()
        if not enabled:
            self.logger.info("Local API disabled (cfg or backend settings).")
            return

        if self._local_api:
            if self._local_api.host == host and self._local_api.port == port:
                return
            self.stop_local_api_server()

        try:
            self._local_api = LocalAccessApiServerV2(app=self, host=host, port=port)
            self._local_api.start()
            self.logger.info(f"Local API started on {host}:{port}")
        except Exception as e:
            self.logger.exception("Failed to start Local API: %s", e)

    def stop_local_api_server(self):
        if self._local_api:
            try:
                self._local_api.stop()
            except Exception:
                pass
        self._local_api = None

    def restart_local_api_server(self):
        self.stop_local_api_server()
        self.start_local_api_server()

    def get_local_api_health(self) -> Dict[str, Any]:
        auth = load_auth_token()
        reasons = self._restriction_reasons()
        summary = self.get_access_mode_summary()
        host, port, enabled = self._effective_local_api_bind()

        return {
            "ok": True,
            "loggedIn": bool(auth and auth.token),
            "restricted": bool(reasons),
            "reasons": reasons,
            "mode": summary,
            "host": host,
            "port": port,
            "enabled": enabled,
            "zkemkeeper": getattr(self, "_zkemkeeper_status", None),
        }

    def reset_runtime_fast_patch_caches(self) -> None:
        try:
            agent_engine = getattr(self, "_agent_engine", None)
            if agent_engine and hasattr(agent_engine, "reset_fast_patch_caches"):
                agent_engine.reset_fast_patch_caches()
        except Exception:
            self.logger.warning("[FastPatch] failed to reset agent caches", exc_info=True)

        try:
            ultra_engine = getattr(self, "_ultra_engine", None)
            if ultra_engine and hasattr(ultra_engine, "reset_fast_patch_caches"):
                ultra_engine.reset_fast_patch_caches()
        except Exception:
            self.logger.warning("[FastPatch] failed to reset ULTRA caches", exc_info=True)

    def apply_fast_patch_bundle(self, bundle: Dict[str, Any]) -> Dict[str, Any]:
        from app.core.db import (
            apply_fast_patch_bundle,
            invalidate_sync_cache,
            refresh_sync_cache_async,
        )

        self._defer_ultra_reconnects(
            trigger_source="FAST_PATCH_BUNDLE",
            duration_sec=20.0,
        )
        db_result = apply_fast_patch_bundle(bundle if isinstance(bundle, dict) else {})
        if db_result.get("ignored") == "duplicate_bundle":
            return {"ok": True, "duplicate": True, **db_result}

        invalidate_sync_cache()
        refresh_sync_cache_async()
        self.reset_runtime_fast_patch_caches()

        items = [item for item in list((bundle or {}).get("items") or []) if isinstance(item, dict)]
        affected_member_ids = {
            int(member_id)
            for item in items
            for member_id in list(((item.get("impact") or {}).get("affectedMemberIds") or []))
            if member_id is not None
        }
        affected_device_ids = {
            int(device_id)
            for item in items
            for device_id in list(((item.get("impact") or {}).get("affectedDeviceIds") or []))
            if device_id is not None
        }
        normalized_types = {
            str(item.get("entityType") or "").strip().upper()
            for item in items
            if item.get("entityType") is not None
        }
        needs_member_refresh = bool(affected_member_ids) or any(
            str(item.get("entityType") or "").strip().upper() == "ACTIVE_MEMBERSHIP"
            for item in items
        )
        needs_device_refresh = any(
            str(item.get("entityType") or "").strip().upper() == "GYM_DEVICE"
            or bool((item.get("impact") or {}).get("requiresDeviceRescope"))
            for item in items
        )
        is_fast_member_bundle = bool(items) and all(
            (
                str(item.get("entityType") or "").strip().upper() == "ACTIVE_MEMBERSHIP"
            ) or (
                str(item.get("entityType") or "").strip().upper() == "CREDENTIALS"
                and str(((item.get("payload") or {}).get("mergeMode") or "")).strip().upper() == "UPSERT_ONLY"
            )
            for item in items
        ) and normalized_types.issubset({"ACTIVE_MEMBERSHIP", "CREDENTIALS"})

        if needs_member_refresh or needs_device_refresh:
            self._request_running_ultra_sync(
                refresh={"members": needs_member_refresh, "devices": needs_device_refresh},
                changed_ids=None if needs_device_refresh else affected_member_ids,
                device_ids=affected_device_ids or None,
                reason="FAST_PATCH_BUNDLE",
            )

        if bool((bundle or {}).get("requiresReconcile", True)) and not is_fast_member_bundle:
            self.request_sync_now(
                trigger_source="FAST_PATCH_BUNDLE",
                run_type="TRIGGERED",
                trigger_hint={"reason": "fast_patch_bundle"},
            )

        return {"ok": True, **db_result}

    # ======================= API helpers =======================
    def _api(self) -> MonClubApi:
        return MonClubApi(endpoints=build_access_api_endpoints(self.cfg), logger=self.logger)

    # ======================= Offline creation queue =======================
    def _auth_token_value(self) -> str:
        auth = load_auth_token()
        tok = getattr(auth, "token", None) if auth else None
        return str(tok or "").strip()

    def attempt_offline_creation(self, *, creation_kind: str, payload: Dict[str, Any], client_request_id: str | None = None) -> Dict[str, Any]:
        kind = str(creation_kind or "membership_only").strip().lower()
        if kind not in ("membership_only", "account_plus_membership"):
            kind = "membership_only"

        token = self._auth_token_value()
        if not token:
            c = classify_failure(http_status=401, message="Authentication required")
            return {
                "ok": False,
                "failureType": c.get("failure_type"),
                "failureCode": c.get("failure_code"),
                "lastHttpStatus": 401,
                "error": "Authentication required. Please re-login.",
                "recommendation": c.get("recommendation") or "save_later",
                "countable": bool(c.get("countable", False)),
            }

        req_id = str(client_request_id or payload.get("clientRequestId") or payload.get("client_request_id") or "").strip()
        if not req_id:
            req_id = str(__import__("uuid").uuid4())

        req_payload = dict(payload or {})
        req_payload["clientRequestId"] = req_id

        try:
            api = self._api()
            if kind == "account_plus_membership":
                resp = api.create_access_account_and_membership(token=token, payload=req_payload)
            else:
                resp = api.create_access_membership(token=token, payload=req_payload)
            if not isinstance(resp, dict):
                resp = {"raw": resp}
            already = bool(resp.get("alreadyExists") or resp.get("idempotentReplay"))
            created = bool(resp.get("created", not already))
            return {
                "ok": True,
                "creationKind": kind,
                "clientRequestId": req_id,
                "created": bool(created),
                "alreadyExists": bool(already),
                "state": "reconciled" if already else "succeeded",
                "result": resp,
            }
        except MonClubApiHttpError as e:
            c = classify_failure(http_status=getattr(e, "status_code", None), message=str(e))
            return {
                "ok": False,
                "failureType": c.get("failure_type"),
                "failureCode": c.get("failure_code"),
                "lastHttpStatus": getattr(e, "status_code", None),
                "error": str(e),
                "recommendation": c.get("recommendation") or "save_later",
                "countable": bool(c.get("countable", False)),
            }
        except Exception as e:
            c = classify_failure(http_status=None, message=str(e))
            return {
                "ok": False,
                "failureType": c.get("failure_type"),
                "failureCode": c.get("failure_code"),
                "lastHttpStatus": None,
                "error": str(e),
                "recommendation": c.get("recommendation") or "save_later",
                "countable": bool(c.get("countable", False)),
            }

    def queue_offline_creation(self, *, creation_kind: str, payload: Dict[str, Any], failure: Dict[str, Any] | None = None) -> Dict[str, Any]:
        f = failure if isinstance(failure, dict) else {}
        ft = str(f.get("failureType") or f.get("failure_type") or "").strip().lower()

        row = insert_offline_creation(
            creation_kind=creation_kind,
            payload=(payload or {}),
            client_request_id=str((payload or {}).get("clientRequestId") or (payload or {}).get("client_request_id") or "").strip() or None,
            state="pending",
            try_to_create=True,
            created=False,
            failure_type=ft or None,
            failure_code=str(f.get("failureCode") or f.get("failure_code") or "").strip() or None,
            last_http_status=f.get("lastHttpStatus"),
            last_error_message=str(f.get("error") or "").strip() or None,
            failed_reason=str(f.get("error") or "").strip() or None,
        )

        if ft:
            updated = mark_offline_creation_failure(
                str(row.get("local_id") or ""),
                failure_type=ft,
                failure_code=str(f.get("failureCode") or f.get("failure_code") or "UNKNOWN"),
                http_status=f.get("lastHttpStatus"),
                message=str(f.get("error") or "Creation failed"),
            )
            if updated:
                return updated

        return row

    def process_offline_creation_row(self, local_id: str, *, source: str = "manual", force: bool = False) -> Dict[str, Any]:
        claimed = claim_offline_creation_for_processing(local_id, force=bool(force))
        if not claimed:
            return {"ok": False, "error": "not-claimable", "localId": local_id}
        payload = claimed.get("payload") if isinstance(claimed.get("payload"), dict) else {}
        if not isinstance(payload, dict):
            payload = {}
        rid = str(claimed.get("client_request_id") or "").strip()
        if rid:
            payload["clientRequestId"] = rid

        kind = str(claimed.get("creation_kind") or "membership_only")
        attempt = self.attempt_offline_creation(creation_kind=kind, payload=payload, client_request_id=rid or None)
        if bool(attempt.get("ok")):
            reconciled = bool(attempt.get("state") == "reconciled" or attempt.get("alreadyExists"))
            row = mark_offline_creation_success(local_id, reconciled=reconciled, result=attempt.get("result") if isinstance(attempt.get("result"), dict) else None)
            return {"ok": True, "row": row, "state": "reconciled" if reconciled else "succeeded", "source": source}
        row = mark_offline_creation_failure(
            local_id,
            failure_type=str(attempt.get("failureType") or "server"),
            failure_code=str(attempt.get("failureCode") or "UNKNOWN"),
            http_status=attempt.get("lastHttpStatus"),
            message=str(attempt.get("error") or "Creation failed"),
        )
        return {"ok": False, "row": row, "state": (row or {}).get("state"), "source": source, "error": attempt.get("error")}

    def process_due_offline_creations(self, *, source: str = "hourly", limit: int = 50) -> Dict[str, Any]:
        if not self._offline_queue_lock.acquire(blocking=False):
            return {"ok": False, "error": "already-running", "processed": 0}
        try:
            due = list_offline_creations_due_for_retry(limit=limit)
            processed = 0
            succeeded = 0
            reconciled = 0
            failed = 0
            for r in due:
                lid = str(r.get("local_id") or "").strip()
                if not lid:
                    continue
                res = self.process_offline_creation_row(lid, source=source, force=False)
                processed += 1
                if bool(res.get("ok")):
                    st = str(res.get("state") or "")
                    if st == "reconciled":
                        reconciled += 1
                    else:
                        succeeded += 1
                else:
                    failed += 1
            self._last_offline_retry_epoch = time.time()
            return {
                "ok": True,
                "processed": processed,
                "succeeded": succeeded,
                "reconciled": reconciled,
                "failed": failed,
                "source": source,
            }
        finally:
            self._offline_queue_lock.release()

    def maybe_run_offline_retry(self, *, sync_online: bool, source: str) -> None:
        prev_online = bool(self._last_sync_online)
        self._last_sync_online = bool(sync_online)
        now_ts = time.time()
        hourly_due = (now_ts - float(self._last_offline_retry_epoch or 0.0)) >= float(self._offline_retry_interval_sec)
        connectivity_restored = bool(sync_online and not prev_online)
        if not sync_online:
            return
        if not hourly_due and not connectivity_restored:
            return
        run_source = "connectivity_restored" if connectivity_restored else source
        try:
            summary = self.process_due_offline_creations(source=run_source, limit=100)
            if summary.get("ok") and int(summary.get("processed") or 0) > 0:
                self.logger.info("[OfflineCreation] processed=%s succeeded=%s reconciled=%s failed=%s source=%s",
                                 summary.get("processed"), summary.get("succeeded"), summary.get("reconciled"), summary.get("failed"), run_source)
        except Exception as ex:
            self.logger.exception("[OfflineCreation] retry run failed: %s", ex)
    # ======================= Sync timer =======================
    def request_sync_now(
        self,
        *,
        trigger_source: str = "SYNC_NOW_API",
        run_type: str = "TRIGGERED",
        trigger_hint: Dict[str, Any] | None = None,
    ):
        normalized_run_type = str(run_type or "TRIGGERED").strip().upper()
        normalized_trigger_source = str(trigger_source or "SYNC_NOW_API").strip().upper()
        normalized_trigger_hint = dict(trigger_hint) if isinstance(trigger_hint, dict) else None
        preserve_pending = (
            self._pending_sync_context is not None
            and normalized_run_type == "TRIGGERED"
            and normalized_trigger_source == "SYNC_NOW_API"
            and normalized_trigger_hint is None
        )
        if not preserve_pending:
            self._pending_sync_context = SyncTriggerContext(
                run_type=normalized_run_type,
                trigger_source=normalized_trigger_source,
                trigger_hint=normalized_trigger_hint,
            )
        self.after(50, self._sync_tick)

    def reschedule_sync_timer(self):
        if self._sync_after_id is not None:
            try:
                self.after_cancel(self._sync_after_id)
            except Exception:
                pass
            self._sync_after_id = None

        # Use backend-driven agentSyncBackendRefreshMin (in minutes) if available,
        # otherwise fall back to local config sync_interval_sec (in seconds).
        # The backend setting is configured in the dashboard under Access Software Settings.
        backend_min = None
        try:
            from app.core.settings_reader import get_backend_global_settings
            gs = get_backend_global_settings() or {}
            val = gs.get("agent_sync_backend_refresh_min")
            if val is not None and int(val) > 0:
                backend_min = int(val)
        except Exception:
            pass
        if backend_min is not None:
            base_interval = backend_min * 60  # convert minutes to seconds
        else:
            interval_cfg = getattr(self.cfg, "sync_interval_sec", 60)
            base_interval = int(max(10, int(interval_cfg)))

        # Exponential backoff on consecutive failures (cap at 10 min)
        if self._sync_fail_count > 0:
            import random
            backoff = min(base_interval * (2 ** self._sync_fail_count), 600)
            interval = int(backoff) + random.randint(0, 10)  # jitter
        else:
            interval = base_interval

        self._sync_after_id = self.after(interval * 1000, self._sync_tick)
        if self._sync_fail_count > 0:
            self.logger.info(f"Sync scheduled in {interval}s (backoff, fails={self._sync_fail_count})")
        else:
            self.logger.info(f"Sync scheduled every {interval} sec")

    def _sync_tick(self):
        self.reschedule_sync_timer()

        if self._sync_work_running:
            self.logger.debug("Sync skipped: previous sync tick still running")
            return

        auth = load_auth_token()
        if not auth:
            self.logger.debug("Sync skipped: no token (not logged in).")
            self.after(0, self.evaluate_access_and_redirect)
            return

        trigger_context, self._startup_sync_pending = resolve_sync_context(
            pending=self._pending_sync_context,
            startup_pending=self._startup_sync_pending,
        )
        self._pending_sync_context = None

        sync_run_id: int | None = None
        sync_started_perf = 0.0

        def work():
            nonlocal sync_run_id, sync_started_perf
            sync_online = False
            sync_run_id = None
            sync_started_perf = time.perf_counter()
            sync_error_message: str | None = None
            device_sync_issue: str | None = None
            sync_response_summary: Dict[str, Any] | None = None
            members_total = 0
            members_changed = 0
            devices_dispatched = 0
            refresh = {
                "members": False,
                "devices": False,
                "credentials": False,
                "settings": False,
            }
            _delta_changed_ids = None  # set when backend returns membersDeltaMode=True

            try:
                from app.core.db import insert_sync_run

                sync_run_id = insert_sync_run(
                    run_type=trigger_context.run_type,
                    trigger_source=trigger_context.trigger_source,
                    trigger_hint=serialize_trigger_hint(trigger_context.trigger_hint),
                    status="IN_PROGRESS",
                    created_at=datetime.now(timezone.utc).isoformat(timespec="seconds"),
                )
            except Exception as ex:
                self.logger.warning("[SyncHistory] Failed to create sync run row: %s", ex)
            try:
                api = self._api()

                # --- Proactive token refresh (before sync so we always use a fresh JWT) ---
                _effective_token = auth.token
                try:
                    if api.do_proactive_refresh(email=auth.email):
                        _reloaded = load_auth_token()
                        if _reloaded and _reloaded.token:
                            _effective_token = _reloaded.token
                            self.logger.info("[SYNC] Access token silently refreshed before sync.")
                except Exception as _prf_exc:
                    self.logger.debug("[SYNC] Proactive refresh skipped/failed: %s", _prf_exc)

                previous_cache = load_sync_cache()
                previous_devices = list(getattr(previous_cache, "devices", []) or []) if previous_cache else []
                stored_version_tokens = load_version_tokens() or None
                version_tokens = apply_trigger_hint_to_version_tokens(
                    stored_version_tokens,
                    trigger_context.trigger_hint,
                )
                if stored_version_tokens and version_tokens != {
                    str(key): str(value)
                    for key, value in stored_version_tokens.items()
                    if value is not None
                }:
                    self.logger.info(
                        "[SYNC-DEBUG] forcing member refresh due to trigger_hint=%s",
                        trigger_context.trigger_hint,
                    )
                # First sync (no tokens) transfers full payload - allow more time.
                # Delta syncs (tokens present) are small and fast - keep tight timeout.
                sync_timeout = 60 if version_tokens else 60

                self.logger.info(
                    "[SYNC-DEBUG] >>> Sending sync request. version_tokens=%s",
                    version_tokens,
                )

                data = api.get_sync_data(token=_effective_token, version_tokens=version_tokens, timeout=sync_timeout)

                # --- DEBUG: log key response fields ---
                _users_raw = data.get("users")
                _users_count = len(_users_raw) if isinstance(_users_raw, list) else f"NOT-A-LIST({type(_users_raw).__name__})"
                self.logger.info(
                    "[SYNC-DEBUG] <<< Response: refreshMembers=%r  users_count=%s  "
                    "refreshDevices=%r  devices_count=%s  "
                    "currentMembersVersion=%r  currentDevicesVersion=%r  "
                    "response_keys=%s",
                    data.get("refreshMembers"), _users_count,
                    data.get("refreshDevices"), len(data.get("devices") or []),
                    data.get("currentMembersVersion"), data.get("currentDevicesVersion"),
                    list(data.keys())[:20],
                )

                refresh = {
                    "members":     data.get("refreshMembers", True),
                    "devices":     data.get("refreshDevices", True),
                    "credentials": data.get("refreshCredentials", True),
                    "settings":    data.get("refreshSettings", True),
                }

                new_tokens = {
                    param: data[field]
                    for param, field in (
                        ("membersVersion",      "currentMembersVersion"),
                        ("devicesVersion",      "currentDevicesVersion"),
                        ("credentialsVersion",  "currentCredentialsVersion"),
                        ("settingsVersion",     "currentSettingsVersion"),
                        ("membersUpdatedAfter", "currentMembersRefreshedAt"),
                    )
                    if data.get(field)
                }

                self._defer_ultra_reconnects(
                    trigger_source=trigger_context.trigger_source,
                    duration_sec=20.0,
                )
                _cache_write_started = time.perf_counter()
                save_sync_cache_delta(data, refresh)
                _cache_write_ms = int((time.perf_counter() - _cache_write_started) * 1000)
                _log_sync_cache_write_profile(self.logger, _cache_write_ms)
                from app.core.db import invalidate_sync_cache, refresh_sync_cache_async
                invalidate_sync_cache()
                refresh_sync_cache_async()

                if (
                    refresh.get("devices")
                    and not refresh.get("members")
                    and device_membership_scope_changed(previous_devices, data.get("devices") or [])
                ):
                    self.logger.warning(
                        "[SYNC-DEBUG] Device membership scope changed without member refresh; "
                        "forcing immediate member follow-up sync."
                    )
                    try:
                        followup_tokens = strip_member_version_tokens(new_tokens)
                        data = api.get_sync_data(
                            token=_effective_token,
                            version_tokens=followup_tokens or None,
                            timeout=sync_timeout,
                        )
                        refresh = {
                            "members":     data.get("refreshMembers", True),
                            "devices":     data.get("refreshDevices", True),
                            "credentials": data.get("refreshCredentials", True),
                            "settings":    data.get("refreshSettings", True),
                        }
                        self._defer_ultra_reconnects(
                            trigger_source=trigger_context.trigger_source,
                            duration_sec=20.0,
                        )
                        save_sync_cache_delta(data, refresh)
                        invalidate_sync_cache()
                        refresh_sync_cache_async()
                        if not refresh.get("members"):
                            clear_version_tokens()
                            new_tokens = {}
                            self.logger.warning(
                                "[SYNC-DEBUG] Forced member follow-up sync still returned refreshMembers=False; "
                                "cleared version tokens for a full retry next cycle."
                            )
                        else:
                            new_tokens = {
                                param: data[field]
                                for param, field in (
                                    ("membersVersion",      "currentMembersVersion"),
                                    ("devicesVersion",      "currentDevicesVersion"),
                                    ("credentialsVersion",  "currentCredentialsVersion"),
                                    ("settingsVersion",     "currentSettingsVersion"),
                                    ("membersUpdatedAfter", "currentMembersRefreshedAt"),
                                )
                                if data.get(field)
                            }
                    except Exception as followup_ex:
                        clear_version_tokens()
                        new_tokens = {}
                        self.logger.warning(
                            "[SYNC-DEBUG] Forced member follow-up sync failed after device scope change; "
                            "cleared version tokens for a full retry next cycle: %s",
                            followup_ex,
                        )

                # Compute delta hints for device push optimization
                if data.get("membersDeltaMode") and refresh.get("members"):
                    _delta_changed_ids = {
                        int(u["activeMembershipId"])
                        for u in (data.get("users") or [])
                        if isinstance(u, dict) and u.get("activeMembershipId") is not None
                    }

                # P6: Member shadow diff — detect actual field changes and update shadow.
                # For full member refreshes this can narrow _delta_changed_ids to only
                # members whose access-relevant fields actually changed (card, name, fps, dates).
                if refresh.get("members"):
                    _shadow_started = time.perf_counter()
                    _delta_changed_ids = self._apply_member_shadow_sync(
                        data=data,
                        refresh=refresh,
                        delta_changed_ids=_delta_changed_ids,
                    )
                    _shadow_ms = int((time.perf_counter() - _shadow_started) * 1000)
                    if _shadow_ms >= 250:
                        self.logger.info("[SYNC-DEBUG] shadow diff/write took %dms", _shadow_ms)

                # Save new version tokens ONLY after successful cache write.
                # Keys must match the Java @RequestParam names exactly so they
                # are recognised on the next request (membersVersion, not currentMembersVersion).
                if new_tokens:
                    save_version_tokens(new_tokens)

                sync_response_summary = build_sync_response_summary(
                    data=data,
                    refresh=refresh,
                    new_tokens=new_tokens,
                )
                members_total = int(
                    sync_response_summary.get("validMemberIdsCount")
                    or sync_response_summary.get("usersCount")
                    or 0
                )
                members_changed = len(_delta_changed_ids) if _delta_changed_ids is not None else 0

                self.logger.info(
                    "getSyncData OK (delta): members=%s devices=%s creds=%s settings=%s  new_tokens=%s",
                    refresh["members"], refresh["devices"], refresh["credentials"], refresh["settings"],
                    new_tokens,
                )
                if refresh.get("members") and not refresh.get("devices"):
                    self._request_running_ultra_sync(
                        refresh=refresh,
                        changed_ids=_delta_changed_ids,
                        reason=trigger_context.trigger_source,
                    )
                sync_online = True
                self._last_sync_at = time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime())
                self._last_sync_ok = True
                self._last_sync_error = None
                self._sync_fail_count = 0  # reset backoff on success

            except Exception as ex:
                self.logger.exception(f"getSyncData failed: {ex} (using cached data if available)")
                sync_online = False
                sync_error_message = str(ex)[:200]
                self._last_sync_at = time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime())
                self._last_sync_ok = False
                self._last_sync_error = sync_error_message
                self._sync_fail_count = min(self._sync_fail_count + 1, 6)  # cap exponent

            # Device sync (DEVICE-mode devices only)
            try:
                if bool(getattr(self.cfg, "device_sync_enabled", True)):
                    reasons = self._restriction_reasons()
                    if reasons:
                        self.logger.warning("[DeviceSync] Skipped: restricted: " + " | ".join(reasons[:3]))
                        if sync_response_summary is not None:
                            sync_response_summary["devicePush"] = {
                                "enabled": True,
                                "started": False,
                                "devicesDispatched": 0,
                                "skippedReason": "RESTRICTED",
                            }
                    else:
                        summary = self.get_access_mode_summary()
                        if summary.get("DEVICE", 0) <= 0:
                            self.logger.info("[DeviceSync] Skipped: no DEVICE-mode devices.")
                            if sync_response_summary is not None:
                                sync_response_summary["devicePush"] = {
                                    "enabled": True,
                                    "started": False,
                                        "devicesDispatched": 0,
                                        "skippedReason": "NO_DEVICE_MODE_DEVICES",
                                    }
                        elif (
                            refresh.get("members")
                            and not refresh.get("devices")
                            and _delta_changed_ids is not None
                            and len(_delta_changed_ids) == 0
                        ):
                            self.logger.info("[DeviceSync] Skipped: no member delta to push.")
                            if sync_response_summary is not None:
                                sync_response_summary["devicePush"] = {
                                    "enabled": True,
                                    "started": False,
                                    "devicesDispatched": 0,
                                    "skippedReason": "NO_MEMBER_DELTA",
                                }
                        else:
                            cache = load_sync_cache()
                            if cache:
                                started = self._device_sync_engine.run_blocking(
                                    cache=cache, source=trigger_context.trigger_source.lower(),
                                    changed_ids=_delta_changed_ids,
                                    sync_run_id=sync_run_id,
                                )
                                if started:
                                    progress_snapshot, _ = self._device_sync_engine.get_progress_snapshot()
                                    devices_dispatched = int(progress_snapshot.get("total") or 0)
                                else:
                                    device_sync_issue = "Device sync already running"
                                if sync_response_summary is not None:
                                    sync_response_summary["devicePush"] = {
                                        "enabled": True,
                                        "started": bool(started),
                                        "devicesDispatched": devices_dispatched,
                                        "skippedReason": "ALREADY_RUNNING" if not started else None,
                                    }
                                self._last_device_sync_at = time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime())
                                self._last_device_sync_ok = bool(started)
                                self._last_device_sync_error = None if started else device_sync_issue
                            else:
                                self.logger.info("[DeviceSync] Skipped: no cache yet")
                                if sync_response_summary is not None:
                                    sync_response_summary["devicePush"] = {
                                        "enabled": True,
                                        "started": False,
                                        "devicesDispatched": 0,
                                        "skippedReason": "NO_CACHE",
                                    }
                else:
                    self.logger.debug("[DeviceSync] Skipped: device sync disabled.")
                    if sync_response_summary is not None:
                        sync_response_summary["devicePush"] = {
                            "enabled": False,
                            "started": False,
                            "devicesDispatched": 0,
                            "skippedReason": "DISABLED",
                        }
            except Exception as ex:
                self._last_device_sync_at = time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime())
                self._last_device_sync_ok = False
                self._last_device_sync_error = str(ex)[:200]
                device_sync_issue = self._last_device_sync_error
                if sync_response_summary is not None:
                    sync_response_summary["devicePush"] = {
                        "enabled": True,
                        "started": False,
                        "devicesDispatched": devices_dispatched,
                        "skippedReason": "ERROR",
                    }
                self.logger.exception(f"[DeviceSync] Unexpected error: {ex}")

            try:
                self._device_attendance_engine.run_blocking(
                    source="timer",
                    sync_online=sync_online,
                    token=auth.token,
                )
            except Exception as ex:
                self.logger.exception("[DeviceAttendance] Unexpected error: %s", ex)

            # --- Agent + ULTRA mode management (synchronized under _ultra_lock
            #     to prevent race condition when devices switch modes) ---
            ultra_engine_restarted = False
            try:
              with self._ultra_lock:
                # Refresh AGENT engine first (stops workers for devices that switched away from AGENT).
                # Must be inside _ultra_lock so AGENT worker teardown completes before ULTRA starts.
                try:
                    if self._agent_engine.is_running():
                        self._agent_engine.refresh_devices()
                except Exception as _agent_exc:
                    self.logger.warning("[AGENT] refresh_devices error: %s", _agent_exc)
                summary = self.get_access_mode_summary()
                ultra_count = summary.get("ULTRA", 0)

                self.logger.info("[ULTRA] sync_tick: mode_summary=%s", summary)
                ultra_devices = []
                if ultra_count > 0:
                    try:
                        from app.core.db import list_sync_devices_payload

                        normalized_devices = list_sync_devices_payload()
                    except Exception:
                        cache = load_sync_cache()
                        normalized_devices = (getattr(cache, "devices", []) or []) if cache else []
                    ultra_devices = [
                        d for d in normalized_devices
                        if isinstance(d, dict) and str(d.get("accessDataMode", "")).strip().upper() == "ULTRA"
                    ]
                    self.logger.info(
                        "[ULTRA] sync_tick: all_devices=%d ultra_devices=%d ids=%s",
                        len(normalized_devices), len(ultra_devices),
                        [d.get("id") for d in ultra_devices],
                    )

                if ultra_count > 0 and not self._ultra_engine.running:
                    if ultra_devices:
                        # Agent engine will naturally drop devices that switched to ULTRA
                        # on its next refresh cycle (it only runs AGENT-mode devices).
                        self._ultra_engine.start(ultra_devices)
                        ultra_engine_restarted = True

                        # Start history consumer for ULTRA engine
                        if not self._ultra_history_consumer:
                            from app.core.realtime_agent import HistoryService
                            from app.core.settings_reader import get_backend_global_settings
                            self._ultra_history_consumer = HistoryService(
                                logger=self.logger,
                                history_q=self._ultra_engine.history_q,
                                global_settings=get_backend_global_settings,
                            )
                            self._ultra_history_consumer.start()

                elif ultra_count > 0 and self._ultra_engine.running:
                    # Check if the device list has changed; restart engine if so.
                    current_ids = set(self._ultra_engine._workers.keys())
                    desired_ids = {int(d.get("id", 0)) for d in ultra_devices}
                    if current_ids != desired_ids:
                        self.logger.info(
                            f"[ULTRA] Device list changed ({current_ids} → {desired_ids}), restarting engine"
                        )
                        self._ultra_engine.stop()
                        if ultra_devices:
                            self._ultra_engine.start(ultra_devices)
                            ultra_engine_restarted = True

                # Stop ULTRA engine if no ULTRA devices remain (switched away from ULTRA)
                if ultra_count == 0 and self._ultra_engine.running:
                    self.logger.info("[ULTRA] No ULTRA devices remaining, stopping engine")
                    self._ultra_engine.stop()
                    if self._ultra_history_consumer:
                        self._ultra_history_consumer.stop()
                        self._ultra_history_consumer = None
            except Exception as ex:
                self.logger.exception(f"[ULTRA] Unexpected error in sync_tick: {ex}")

            if refresh.get("devices") and not ultra_engine_restarted:
                self._request_running_ultra_sync(
                    refresh=refresh,
                    changed_ids=None,
                    reason=trigger_context.trigger_source,
                )

            try:
                self.maybe_run_offline_retry(sync_online=sync_online, source="hourly")
            except Exception:
                pass

            try:
                if sync_run_id is not None:
                    from app.core.db import prune_push_batch_history, prune_sync_run_history, update_sync_run
                    import json

                    final_status = "SUCCESS"
                    final_error = device_sync_issue
                    if sync_error_message:
                        final_status = "FAILED"
                        final_error = sync_error_message
                    elif device_sync_issue:
                        final_status = "PARTIAL"

                    update_sync_run(
                        id=sync_run_id,
                        status=final_status,
                        members_total=members_total,
                        members_changed=members_changed,
                        devices_synced=devices_dispatched,
                        duration_ms=int((time.perf_counter() - sync_started_perf) * 1000),
                        error_message=final_error,
                        raw_response=json.dumps(sync_response_summary or {}, ensure_ascii=False),
                    )
                    self._maybe_emit_sync_success_feedback(
                        sync_run_id=sync_run_id,
                        final_status=final_status,
                        trigger_context=trigger_context,
                    )
                    prune_sync_run_history(retention_days=30)
                    prune_push_batch_history(retention_days=30)
            except Exception as ex:
                self.logger.warning("[SyncHistory] Failed to finalize sync run row: %s", ex)



            self.after(0, self.evaluate_access_and_redirect)
        _work_original = work
        def _work_guarded():
            try:
                _work_original()
            except Exception:
                self.logger.exception("[SyncHistory] work() crashed unexpectedly -- sync run may be orphaned")
            finally:
                # Safety net: if work() crashed before its own finalization block, the
                # sync run row may still be IN_PROGRESS. Detect and finalize it here.
                try:
                    if sync_run_id is not None:
                        from app.core.db import get_sync_run, update_sync_run
                        row = get_sync_run(sync_run_id)
                        if row and str(row.get("status", "")).upper() == "IN_PROGRESS":
                            update_sync_run(
                                id=sync_run_id,
                                status="FAILED",
                                duration_ms=int((time.perf_counter() - sync_started_perf) * 1000),
                                error_message="Sync work crashed or was interrupted before completing",
                            )
                except Exception as _fin_ex:
                    self.logger.warning("[SyncHistory] Safety-net finalization failed: %s", _fin_ex)
                self._sync_work_running = False
        self._sync_work_running = True
        threading.Thread(target=_work_guarded, daemon=True).start()

    # ======================= Access rules =======================
    def _restriction_reasons(self) -> list[str]:
        reasons: list[str] = []
        auth = load_auth_token()
        if not auth:
            return reasons

        dt_login = _parse_dt_any(auth.last_login_at)
        max_age_cfg = getattr(self.cfg, "max_login_age_minutes", 43200)

        if dt_login is None:
            reasons.append("Last login date missing/invalid. Please login again.")
        else:
            age = datetime.now() - dt_login
            if age > timedelta(minutes=int(max_age_cfg)):
                days_expired = age.days
                reasons.append(f"Votre session a expirée (dernière connexion il y a {days_expired} jours). Veuillez vous reconnecter.")

        contract_meta = None
        cache = None
        try:
            from app.core.db import load_sync_contract_meta, peek_sync_cache

            cache = peek_sync_cache()
            if cache is None:
                contract_meta = load_sync_contract_meta()
        except Exception:
            contract_meta = None

        if cache is not None:
            contract_status = getattr(cache, "contract_status", getattr(cache, "contractStatus", None))
            contract_end_date = getattr(cache, "contract_end_date", getattr(cache, "contractEndDate", None))
        elif contract_meta is None:
            cache = load_sync_cache()
            if cache:
                contract_status = getattr(cache, "contract_status", getattr(cache, "contractStatus", None))
                contract_end_date = getattr(cache, "contract_end_date", getattr(cache, "contractEndDate", None))
            else:
                contract_status = None
                contract_end_date = None
        else:
            contract_status = contract_meta.get("contractStatus")
            contract_end_date = contract_meta.get("contractEndDate")

        if contract_status is False:
            reasons.append("Contract inactive (status=false from backend).")

        if contract_end_date:
            end_dt = _parse_dt_any(str(contract_end_date))
            if end_dt and end_dt < datetime.now():
                reasons.append(f"Contract expired (contractEndDate={contract_end_date}).")
        elif contract_meta is None:
            self.logger.warning("No sync cache yet (contract checks cannot be evaluated offline).")

        return reasons

    def _compute_expiry_warnings(self) -> dict:
        result = {
            "loginDaysRemaining": None, "loginWarning": False,
            "contractDaysRemaining": None, "contractWarning": False,
        }
        auth = load_auth_token()
        if auth:
            dt_login = _parse_dt_any(auth.last_login_at)
            max_age_cfg = getattr(self.cfg, "max_login_age_minutes", 43200)
            if dt_login is not None:
                expiry_dt = dt_login + timedelta(minutes=int(max_age_cfg))
                remaining = expiry_dt - datetime.now()
                days_remaining = remaining.days
                if days_remaining < 0:
                    days_remaining = 0
                result["loginDaysRemaining"] = days_remaining
                if days_remaining <= 7:
                    result["loginWarning"] = True

        try:
            from app.core.db import load_sync_contract_meta

            contract_meta = load_sync_contract_meta()
        except Exception:
            contract_meta = None

        if contract_meta is None:
            cache = load_sync_cache()
            contract_end_date = getattr(cache, "contract_end_date", getattr(cache, "contractEndDate", None)) if cache else None
        else:
            contract_end_date = contract_meta.get("contractEndDate")

        end_dt = _parse_dt_any(str(contract_end_date or ""))
        if end_dt is not None:
            remaining = end_dt - datetime.now()
            days_remaining = remaining.days
            if days_remaining < 0:
                days_remaining = 0
            result["contractDaysRemaining"] = days_remaining
            if days_remaining <= 10:
                result["contractWarning"] = True
        return result

    def evaluate_access_and_redirect(self):
        auth = load_auth_token()

        if not auth:
            try:
                self._update_manager.stop()
            except Exception:
                pass
            self.show_login()
            return

        try:
            self._ensure_update_manager_started(check_now=False)
        except Exception:
            pass

        reasons = self._restriction_reasons()
        if reasons:
            self.show_restricted()
            return

        self.show_app()
        self.apply_realtime_agent_from_config()

    # ======================= Expiry warnings =======================
    _expiry_notif_last_date: str = ""

    def start_expiry_warning_scheduler(self):
        self._check_expiry_warnings()
        self.after(3600_000, self.start_expiry_warning_scheduler)

